import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import CodeMirror from '@uiw/react-codemirror';
import { python } from '@codemirror/lang-python';
import { api } from '../services/api';
import './ProblemSolverPage.css';

function ProblemSolverPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [problem, setProblem] = useState(null);
  const [code, setCode] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [testCases, setTestCases] = useState([]);
  const [activeTab, setActiveTab] = useState('testcase');

  useEffect(() => {
    loadProblem();
  }, [id]);

  const loadProblem = async () => {
    try {
      const [problemData, template, testCasesData] = await Promise.all([
        api.getProblem(id),
        api.getTemplate(id),
        api.getTestCases(id)
      ]);
      setProblem(problemData);
      setCode(template.template_code || '');
      setTestCases(testCasesData);
    } catch (error) {
      console.error('Failed to load problem:', error);
    }
  };

  const handleSubmit = async () => {
    if (!code.trim()) {
      alert('Please write some code!');
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const res = await api.submitCode({ 
        problem: parseInt(id), 
        code: code 
      });
      setResult(res);

      if (res.status === 'Accepted') {
        alert('✅ Accepted! Great job!');
      } else {
        alert(`❌ ${res.status}`);
      }

      // Switch to result tab
      setActiveTab('result');
    } catch (error) {
      console.error('Submission error:', error);
      alert('Submission failed: ' + (error.response?.data?.detail || error.message));
    } finally {
      setLoading(false);
    }
  };

  if (!problem) return <div className="loading">Loading...</div>;

  return (
    <div className="solver-page">
      <nav className="navbar">
        <button onClick={() => navigate('/problems')} className="btn-back">
          ← Back
        </button>
        <div className="nav-brand">{problem.title}</div>
      </nav>

      <div className="solver-layout">
        <div className="problem-panel">
          <h2>{problem.title}</h2>
          <span className={`badge ${problem.difficulty}`}>{problem.difficulty}</span>
          <div className="description">{problem.description}</div>
          <div className="example">
            <h3>Example</h3>
            <div><strong>Input:</strong> {problem.input_example}</div>
            <div><strong>Output:</strong> {problem.output_example}</div>
          </div>
        </div>

        <div className="editor-panel">
          <div className="editor-header">
            <div className="editor-tabs">
              <div className="editor-tab active">
                <i className="fab fa-python"></i> Python
              </div>
            </div>
            <button 
              onClick={handleSubmit} 
              disabled={loading}
              className="btn-run"
            >
              {loading ? '⏳ Running...' : '▶ Run Code'}
            </button>
          </div>

          <CodeMirror
            value={code}
            height="100%"
            theme="dark"
            extensions={[python()]}
            onChange={(value) => setCode(value)}
            className="code-mirror-editor"
            basicSetup={{
              lineNumbers: true,
              highlightActiveLineGutter: true,
              highlightSpecialChars: true,
              foldGutter: true,
              drawSelection: true,
              dropCursor: true,
              allowMultipleSelections: true,
              indentOnInput: true,
              bracketMatching: true,
              closeBrackets: true,
              autocompletion: true,
              rectangularSelection: true,
              crosshairCursor: true,
              highlightActiveLine: true,
              highlightSelectionMatches: true,
              closeBracketsKeymap: true,
              searchKeymap: true,
              foldKeymap: true,
              completionKeymap: true,
              lintKeymap: true,
            }}
          />

          {result && (
            <div className={`result ${result.status === 'Accepted' ? 'success' : 'error'}`}>
              <div><strong>Status:</strong> {result.status}</div>
              <div><strong>Time:</strong> {result.execution_time}ms</div>

              {result.status !== 'Accepted' && (
                <>
                  {result.failed_test && (
                    <div><strong>Failed Test:</strong> {result.failed_test}</div>
                  )}
                  {result.error_input && (
                    <div><strong>Input:</strong> {result.error_input}</div>
                  )}
                  {result.error_output && (
                    <div><strong>Your Output:</strong> {result.error_output}</div>
                  )}
                  {result.error_expected && (
                    <div><strong>Expected:</strong> {result.error_expected}</div>
                  )}
                </>
              )}

              {result.status === 'Accepted' && (
                <div style={{textAlign: 'center', padding: '1rem'}}>
                  <div style={{fontSize: '3rem'}}>🎉</div>
                  <div><strong>Score:</strong> {result.user_score}</div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default ProblemSolverPage;
